import React, { useState } from 'react';
import { Link } from 'react-router-dom';

const NavigationBar = () => {
  const [chainState, setChainState] = useState('ethereum');

  const toggleChain = () => {
    setChainState(prevState => prevState === 'ethereum' ? 'pulsechain' : 'ethereum');
  };

  const navStyle = {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '10px 20px',
    backgroundColor: 'black',
    color: 'white',
    fontFamily: 'Arial, sans-serif',
  };

  const linkStyle = {
    color: 'white',
    textDecoration: 'none',
    marginRight: '20px',
  };

  const buttonStyle = {
    backgroundColor: 'white',
    border: 'none',
    borderRadius: '5px',
    padding: '5px 10px',
    marginRight: '10px',
    cursor: 'pointer',
  };

  const buyButtonStyle = {
    backgroundColor: 'black',
    color: 'white',
    border: '1px solid white',
    borderRadius: '5px',
    padding: '5px 15px',
    cursor: 'pointer',
  };

  return (
    <nav style={navStyle}>
      <div>
        <Link to="/" style={linkStyle}>LookIntoMaxi</Link>
        <Link to="/delta-discounts" style={linkStyle}>Δ Discounts</Link>
        <Link to="/percent-discounts" style={linkStyle}>% Discounts</Link>
        <Link to="/arbs" style={linkStyle}>Arbs</Link>
        <Link to="/apy" style={linkStyle}>Apy</Link>
        <Link to="/leagues" style={linkStyle}>Leagues</Link>
        <Link to="/gas" style={linkStyle}>Gas</Link>
      </div>
      <div>
        <button onClick={toggleChain} style={buttonStyle}>
          {chainState === 'ethereum' ? '▼' : '〰️'}
        </button>
        <Link to="/buy" style={buyButtonStyle}>Buy</Link>
      </div>
    </nav>
  );
};

export default NavigationBar;
